+
+    local procedure NormalizeDemandLineFilter(OriginalFilter: Text): Text
+    var
+        FilterParts: List of [Text];
+        NormalizedParts: List of [Text];
+        CurrentPart: Text;
+        RangeStart: Integer;
+        RangeEnd: Integer;
+        DotPos: Integer;
+        i: Integer;
+    begin
+        if OriginalFilter = '' then
+            exit('');
+
+        // Split filter by '|' to handle multiple conditions
+        FilterParts := OriginalFilter.Split('|');
+
+        for i := 1 to FilterParts.Count do begin
+            CurrentPart := FilterParts.Get(i);
+            CurrentPart := CurrentPart.Trim();
+
+            // Check if this part contains '..' (range operator)
+            DotPos := StrPos(CurrentPart, '..');
+            if DotPos > 0 then begin
+                // Extract the start and end values
+                RangeStart := StrToIntDef(CopyStr(CurrentPart, 1, DotPos - 1), 0);
+                RangeEnd := StrToIntDef(CopyStr(CurrentPart, DotPos + 2), 0);
+
+                // Swap if necessary to ensure start <= end
+                if RangeStart > RangeEnd then begin
+                    i := RangeStart;
+                    RangeStart := RangeEnd;
+                    RangeEnd := i;
+                end;
+
+                NormalizedParts.Add(Format(RangeStart) + '..' + Format(RangeEnd));
+            end else begin
+                // Single value, keep as is
+                NormalizedParts.Add(CurrentPart);
+            end;
+        end;
+
+        // Reconstruct the filter
+        exit(string.Join(NormalizedParts, '|'));
+    end;
 }
+
