+    [EventSubscriber(ObjectType::Table, Database::"Transfer Line", 'OnBeforeValidateEvent', 'Reserved Quantity Outbnd.', false, false)]
+    local procedure CheckReserveMethodOnBeforeValidateReservedQtyOutbound(var Rec: Record "Transfer Line"; var xRec: Record "Transfer Line")
+    var
+        Item: Record Item;
+        ReserveErr: Label 'Item %1 cannot be reserved.', Comment = '%1 = Item No.';
+    begin
+        if Rec.IsTemporary() then
+            exit;
+
+        // Check if Reserved Quantity is being increased (attempting to reserve)
+        if Rec."Reserved Quantity Outbnd." > xRec."Reserved Quantity Outbnd." then begin
+            if Item.Get(Rec."Item No.") then begin
+                if Item.Reserve = Item.Reserve::Never then
+                    Error(ReserveErr, Rec."Item No.");
+            end;
+        end;
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Transfer Line", 'OnBeforeValidateEvent', 'Reserved Qty. (Base)', false, false)]
