+    var
+        Item: Record Item;
+        ReserveErr: Label 'Item %1 cannot be reserved.', Comment = '%1 = Item No.';
+    begin
+        if Rec.IsTemporary() then
+            exit;
+
+        // Check if Reserved Quantity (Base) is being increased (attempting to reserve)
+        if Rec."Reserved Qty. (Base)" > xRec."Reserved Qty. (Base)" then begin
+            if Item.Get(Rec."Item No.") then begin
+                if Item.Reserve = Item.Reserve::Never then
+                    Error(ReserveErr, Rec."Item No.");
+            end;
+        end;
+    end;
